import { GoogleGenAI } from "@google/genai";
import { Message } from "../types";

const MODEL_NAME = "gemini-3-flash-preview";

const SYSTEM_INSTRUCTION_TEMPLATE = `
You are a Senior Retail Performance Analyst.
You have access to a dataset from a retail chain (provided below in CSV format).

YOUR GOALS:
1. Answer user queries about store, region, or national performance.
2. Always analyze data in two periods if available: "Annual" (YTD) and "Monthly".
3. CRITICAL: Compare specific store performance against "National" and their respective "Region" averages.
4. Detect Deviations: Identify metrics where a store is underperforming compared to the benchmarks (National/Region).
5. Prioritize Improvements: Based on the deviations, suggest top priorities. (e.g., if Conversion is low but Traffic is high, prioritize sales training).

FORMATTING RULES:
- Use Markdown.
- Use **Bold** for key metrics and store names.
- Use Tables to show side-by-side comparisons (Store vs Region vs National).
- Keep answers professional, concise, and action-oriented.

DATASET:
`;

export const sendMessageToGemini = async (
  apiKey: string,
  history: Message[],
  currentMessage: string,
  csvData: string
): Promise<string> => {
  if (!apiKey) throw new Error("API Key is required");

  const ai = new GoogleGenAI({ apiKey });

  // Filter history to only include valid exchange for context, avoiding clutter
  // We strictly use the chat structure required by the SDK or simple generateContent with history context
  // Here we will use generateContent to have full control over system instructions with the dynamic CSV

  const prompt = `
  User Query: ${currentMessage}
  `;

  // Construct previous conversation context manually for the prompt to ensure state is preserved
  // limiting to last 6 messages to save context window tokens if data is huge
  const conversationContext = history.slice(-6).map(m => `${m.role.toUpperCase()}: ${m.content}`).join('\n');

  const fullPrompt = `
  ${conversationContext}
  USER: ${currentMessage}
  MODEL:
  `;

  try {
    const response = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: fullPrompt,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION_TEMPLATE + csvData,
        thinkingConfig: { thinkingBudget: 0 } // Disable thinking for faster, standard chat response
      }
    });

    return response.text || "I processed the data but could not generate a text response.";
  } catch (error: any) {
    console.error("Gemini API Error:", error);
    throw new Error(error.message || "Failed to communicate with Gemini.");
  }
};

import React, { useState, useEffect } from 'react';
import { Key } from 'lucide-react';

interface ApiKeyModalProps {
  isOpen: boolean;
  onSave: (key: string) => void;
}

export const ApiKeyModal: React.FC<ApiKeyModalProps> = ({ isOpen, onSave }) => {
  const [key, setKey] = useState('');

  useEffect(() => {
    // Check if env var exists (for dev convenience) or localStorage
    const stored = localStorage.getItem('gemini_api_key');
    if (stored) setKey(stored);
    else if (process.env.API_KEY) setKey(process.env.API_KEY);
  }, []);

  if (!isOpen) return null;

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (key.trim()) {
      localStorage.setItem('gemini_api_key', key);
      onSave(key);
    }
  };

  return (
    <div className="fixed inset-0 bg-black/70 flex items-center justify-center z-50 p-4">
      <div className="bg-white rounded-xl shadow-2xl max-w-md w-full p-6">
        <div className="flex items-center gap-3 mb-4 text-blue-600">
          <div className="p-3 bg-blue-100 rounded-full">
            <Key size={24} />
          </div>
          <h2 className="text-xl font-bold text-gray-800">API Key Required</h2>
        </div>

        <p className="text-gray-600 mb-6 text-sm">
          To analyze your Google Sheet data with Gemini 2.5/3.0, please provide your Google GenAI API Key.
          The key is stored locally in your browser.
        </p>

