};

import React from 'react';
import { Message } from '../types';
import { Bot, User, Clock } from 'lucide-react';

interface ChatBubbleProps {
  message: Message;
}

export const ChatBubble: React.FC<ChatBubbleProps> = ({ message }) => {
  const isBot = message.role === 'model';

  // Basic formatting for the demo: handle bolding and newlines
  const formatText = (text: string) => {
    return text.split('\n').map((line, i) => {
      // Very basic bold parser for **text**
      const parts = line.split(/(\*\*.*?\*\*)/g);
      return (
        <div key={i} className="min-h-[1.2em]">
          {parts.map((part, j) => {
            if (part.startsWith('**') && part.endsWith('**')) {
              return <strong key={j}>{part.slice(2, -2)}</strong>;
            }
            return <span key={j}>{part}</span>;
          })}
        </div>
      );
    });
  };

  return (
    <div className={`flex w-full mb-6 ${isBot ? 'justify-start' : 'justify-end'}`}>
      <div className={`flex max-w-[85%] md:max-w-[75%] gap-3 ${isBot ? 'flex-row' : 'flex-row-reverse'}`}>

        {/* Avatar */}
        <div className={`flex-shrink-0 w-8 h-8 rounded-full flex items-center justify-center mt-1 shadow-sm ${
          isBot ? 'bg-indigo-100 text-indigo-600' : 'bg-gray-200 text-gray-600'
        }`}>
          {isBot ? <Bot size={18} /> : <User size={18} />}
        </div>

        {/* Bubble */}
        <div className={`flex flex-col ${isBot ? 'items-start' : 'items-end'}`}>
          <div className={`px-5 py-3.5 rounded-2xl shadow-sm text-sm leading-relaxed whitespace-pre-wrap ${
            isBot 
              ? 'bg-white text-gray-800 border border-gray-100 rounded-tl-none' 
              : 'bg-indigo-600 text-white rounded-tr-none'
          }`}>
             {isBot ? (
                // For bot, we render somewhat raw to support the formatting helper
                <div className="space-y-1">{formatText(message.content)}</div>
             ) : (
                message.content
             )}
          </div>

          <div className="flex items-center gap-1 mt-1 text-xs text-gray-400 px-1">
             <Clock size={10} />
             <span>{message.timestamp.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}</span>
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Database, RefreshCw, AlertTriangle, FileText, CheckCircle2 } from 'lucide-react';
import { DEFAULT_SHEET_CONFIG, fetchSheetData, MOCK_DATA } from '../services/sheet';

interface DataPanelProps {
  onDataLoaded: (data: string) => void;
  currentData: string | null;
}

export const DataPanel: React.FC<DataPanelProps> = ({ onDataLoaded, currentData }) => {
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [mode, setMode] = useState<'url' | 'manual'>('url');
  const [manualText, setManualText] = useState('');

  const handleFetch = async () => {
    setLoading(true);
    setError(null);
    try {
      const data = await fetchSheetData(DEFAULT_SHEET_CONFIG);
      onDataLoaded(data);
    } catch (err: any) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  const loadMockData = () => {
    onDataLoaded(MOCK_DATA);
    setManualText(MOCK_DATA);
    setMode('manual');
    setError(null);
  };

  const handleManualSubmit = () => {
    if(!manualText.trim()) return;
    onDataLoaded(manualText);
  };

  return (
    <div className="bg-white border-b border-gray-200 p-4 md:p-6">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 mb-4">
        <div className="flex items-center gap-2 text-gray-800">
           <div className="p-2 bg-indigo-50 rounded-lg text-indigo-600">
             <Database size={20} />
           </div>
           <div>
             <h2 className="font-semibold">Data Source</h2>
             <p className="text-xs text-gray-500">
                {currentData 
                  ? `${currentData.split('\n').length} rows loaded` 
                  : 'No data context loaded'}
             </p>
           </div>
        </div>

        <div className="flex gap-2">
           <button 
             onClick={() => setMode('url')}
             className={`px-3 py-1.5 text-xs font-medium rounded-md transition-colors ${mode === 'url' ? 'bg-gray-100 text-gray-900' : 'text-gray-500 hover:text-gray-900'}`}
           >
             Live Sheet
           </button>
           <button 
             onClick={() => setMode('manual')}
             className={`px-3 py-1.5 text-xs font-medium rounded-md transition-colors ${mode === 'manual' ? 'bg-gray-100 text-gray-900' : 'text-gray-500 hover:text-gray-900'}`}
           >
             Raw/Manual
           </button>
        </div>
      </div>

      {mode === 'url' && (
        <div className="space-y-3">
          <div className="flex items-center gap-2 p-3 bg-gray-50 rounded-lg border border-gray-200 text-sm">
             <FileText size={16} className="text-gray-400" />
             <span className="truncate flex-1 text-gray-600 font-mono text-xs">
               ...{DEFAULT_SHEET_CONFIG.sheetId.slice(0, 15)}... / GID: {DEFAULT_SHEET_CONFIG.gid}
             </span>
             <button 
                onClick={handleFetch}
                disabled={loading}
                className="flex items-center gap-1.5 px-3 py-1 bg-indigo-600 hover:bg-indigo-700 text-white rounded text-xs font-medium transition-colors disabled:opacity-50"
             >
                {loading ? <RefreshCw size={12} className="animate-spin" /> : <RefreshCw size={12} />}
                {loading ? 'Fetching...' : 'Connect'}
             </button>
          </div>

          {error && (
            <div className="p-3 bg-red-50 border border-red-100 rounded-lg flex items-start gap-2 text-xs text-red-700">
              <AlertTriangle size={14} className="mt-0.5 flex-shrink-0" />
              <div className="flex-1">
                <p className="font-bold mb-1">Connection Failed</p>
                <p className="opacity-90">{error}</p>
                <button 
                  onClick={loadMockData}
                  className="mt-2 text-red-800 underline hover:text-red-900 font-medium"
                >
                  Load Demo Data instead
                </button>
              </div>
            </div>
          )}
        </div>
      )}

      {mode === 'manual' && (
        <div className="space-y-3">
          <textarea
            value={manualText}
            onChange={(e) => setManualText(e.target.value)}
            placeholder="Paste CSV data here: Store, Region, Period, Sales..."
            className="w-full h-24 p-3 text-xs font-mono border border-gray-300 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500"
          />
          <div className="flex justify-end gap-2">
            <button 
               onClick={loadMockData}
               className="text-xs text-gray-500 hover:text-indigo-600 underline"
            >
              Use Demo Data
            </button>
            <button 
              onClick={handleManualSubmit}
              className="px-4 py-1.5 bg-gray-900 text-white text-xs font-medium rounded hover:bg-black transition-colors"
            >
              Update Context
            </button>
          </div>
        </div>
      )}

      {currentData && !error && (
        <div className="mt-2 flex items-center gap-1.5 text-green-600 text-xs font-medium">
          <CheckCircle2 size={12} />
          <span>Analyst is ready with updated data.</span>
        </div>
      )}
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { Send, Sparkles, AlertCircle } from 'lucide-react';
import { ApiKeyModal } from './components/ApiKeyModal';
import { ChatBubble } from './components/ChatBubble';
import { DataPanel } from './components/DataPanel';
import { Message } from './types';
import { sendMessageToGemini } from './services/gemini';

export default function App() {
  const [apiKey, setApiKey] = useState<string>('');
  const [isKeyModalOpen, setKeyModalOpen] = useState(false);

  const [dataContext, setDataContext] = useState<string | null>(null);
  const [messages, setMessages] = useState<Message[]>([
    {
      id: 'welcome',
      role: 'model',
      content: "Hello! I'm your Retail Performance Analyst. \n\nPlease load the latest store data above to get started. Once loaded, you can ask me to analyze annual or monthly performance, compare regions, or suggest priorities.",
      timestamp: new Date()
    }
  ]);
  const [input, setInput] = useState('');
  const [isSending, setIsSending] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    // Initial check for key
    const storedKey = localStorage.getItem('gemini_api_key') || process.env.API_KEY;
    if (storedKey) {
        setApiKey(storedKey);
    } else {
        setKeyModalOpen(true);
    }
  }, []);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const handleSendMessage = async (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!input.trim() || isSending) return;
    if (!dataContext) {
      alert("Please connect to the Google Sheet or load data first.");
      return;
    }
    if (!apiKey) {
      setKeyModalOpen(true);
      return;
    }

    const newUserMsg: Message = {
      id: Date.now().toString(),
      role: 'user',
      content: input,
      timestamp: new Date()
    };

    setMessages(prev => [...prev, newUserMsg]);
    setInput('');
    setIsSending(true);

    try {
      const responseText = await sendMessageToGemini(apiKey, messages, input, dataContext);
      const botMsg: Message = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        content: responseText,
        timestamp: new Date()
      };
      setMessages(prev => [...prev, botMsg]);
    } catch (error: any) {
      const errorMsg: Message = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        content: `**Error**: ${error.message}`,
        timestamp: new Date()
      };
      setMessages(prev => [...prev, errorMsg]);
    } finally {
      setIsSending(false);
    }
  };

  return (
    <div className="flex flex-col h-screen bg-gray-50 font-sans text-gray-900">
      <ApiKeyModal 
        isOpen={isKeyModalOpen} 
        onSave={(key) => {
          setApiKey(key);
          setKeyModalOpen(false);
        }} 
      />

      {/* Header */}
      <header className="flex-shrink-0 bg-white border-b border-gray-200 px-6 py-4 flex items-center justify-between sticky top-0 z-20">
        <div className="flex items-center gap-2 text-indigo-700">
          <Sparkles size={24} />
          <h1 className="text-xl font-bold tracking-tight">Retail KPI Analyst</h1>
        </div>
        <div className="flex items-center gap-4">
            <button 
              onClick={() => setKeyModalOpen(true)}
              className="text-xs text-gray-400 hover:text-indigo-600 font-medium"
            >
              {apiKey ? 'API Key Configured' : 'Set API Key'}
            </button>
        </div>
      </header>

      {/* Main Content Area: Split View for larger screens, Stacked for mobile */}
      <div className="flex-1 flex flex-col md:flex-row overflow-hidden">

        {/* Left Panel: Data & Context Config */}
        <div className="w-full md:w-80 lg:w-96 flex-shrink-0 bg-gray-100/50 md:border-r border-gray-200 overflow-y-auto">
          <DataPanel 
            onDataLoaded={(data) => {
                setDataContext(data);
                if (messages.length === 1) {
                    setMessages(prev => [...prev, {
                        id: 'system-ready',
                        role: 'model',
                        content: "**Data loaded successfully.** \n\nI can now see the Sales, Traffic, and KPI data. Try asking: \n\n*\"How is Store Seville Plaza performing compared to the region?\"*\n*\"What are the top priorities for improvement in the North region?\"*",
                        timestamp: new Date()
                    }]);
                }
            }}
            currentData={dataContext}
          />

          <div className="p-6">
            <h3 className="text-xs font-semibold text-gray-400 uppercase tracking-wider mb-3">Analysis Capabilities</h3>
            <ul className="space-y-3 text-sm text-gray-600">
              <li className="flex gap-2">
                <span className="w-1.5 h-1.5 rounded-full bg-green-500 mt-1.5"></span>
                <span>Annual vs Monthly Performance</span>
              </li>
              <li className="flex gap-2">
                <span className="w-1.5 h-1.5 rounded-full bg-blue-500 mt-1.5"></span>
                <span>Regional Benchmarking</span>
              </li>
              <li className="flex gap-2">
                <span className="w-1.5 h-1.5 rounded-full bg-purple-500 mt-1.5"></span>
                <span>Deviation Detection</span>
              </li>
              <li className="flex gap-2">
                <span className="w-1.5 h-1.5 rounded-full bg-orange-500 mt-1.5"></span>
                <span>Improvement Priorities</span>
              </li>
            </ul>
          </div>
        </div>

        {/* Right Panel: Chat Interface */}
        <div className="flex-1 flex flex-col relative bg-gray-50/50">

          {/* Messages Area */}
          <div className="flex-1 overflow-y-auto p-4 md:p-8 scroll-smooth">
            <div className="max-w-3xl mx-auto">
              {messages.map((msg) => (
                <ChatBubble key={msg.id} message={msg} />
              ))}
              {isSending && (
                 <div className="flex justify-start mb-6 w-full animate-pulse">
                   <div className="bg-white border border-gray-100 px-5 py-3 rounded-2xl rounded-tl-none shadow-sm flex items-center gap-2">
                      <div className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce"></div>
                      <div className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce delay-75"></div>
                      <div className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce delay-150"></div>
                   </div>
                 </div>
              )}
              <div ref={messagesEndRef} />
            </div>
          </div>

          {/* Input Area */}
          <div className="p-4 md:p-6 bg-white border-t border-gray-200">
            <form onSubmit={handleSendMessage} className="max-w-3xl mx-auto relative flex items-center gap-3">
               {!dataContext && (
                 <div className="absolute -top-12 left-0 right-0 flex justify-center">
                    <div className="bg-yellow-50 text-yellow-800 text-xs px-3 py-1.5 rounded-full border border-yellow-200 flex items-center gap-1.5 shadow-sm">
                        <AlertCircle size={12} />
                        Load data to start analyzing
                    </div>
                 </div>
               )}
               <input
                 type="text"
                 value={input}
                 onChange={(e) => setInput(e.target.value)}
                 disabled={isSending}
                 placeholder="Ask about store performance, deviations, or priorities..."
                 className="flex-1 bg-gray-100 text-gray-900 placeholder-gray-500 border-0 rounded-xl px-5 py-4 focus:ring-2 focus:ring-indigo-500 focus:bg-white transition-all outline-none"
               />
               <button
                 type="submit"
                 disabled={!input.trim() || isSending || !dataContext}
                 className="p-4 bg-indigo-600 hover:bg-indigo-700 disabled:bg-gray-300 disabled:cursor-not-allowed text-white rounded-xl shadow-lg hover:shadow-xl transition-all flex items-center justify-center transform hover:scale-105 active:scale-95"
               >
                 <Send size={20} />
               </button>
            </form>
            <p className="text-center text-xs text-gray-400 mt-3">
              AI analyzes the loaded dataset. Verify critical business decisions independently.
            </p>
          </div>

        </div>
      </div>
    </div>
  );
}
